const original = $input.first().json.output || '';

// 1. החלף ** ב-*
let cleaned = original.replace(/\*\*/g, '*');

// 2. הסר תווים מיוחדים נפוצים
cleaned = cleaned
  .replace(/[\[\]\(\)\`]/g, '')      // סוגריים עגולות ומרובעות + backticks
  .replace(/\*/g, '')                // כוכביות
  .replace(/\u200b/g, '')            // zero-width space
  .replace(/[“”‘’]/g, '"')           // מירכאות חכמות
  .replace(/[—–]/g, '-')             // מקפים מיוחדים
  // .replace(/[📎]/g, '')              // הסר אמוג'ים נפוצים (אפשר להוסיף עוד)
  .replace(/([^\s])https?:\/\//g, '$1 https://'); // רווח לפני לינק אם אין רווח

// 3. הסר תווים לא־ASCII אם נדרש (אופציונלי)
// cleaned = cleaned.replace(/[^\x00-\x7F]+/g, '');

return [
  {
    json: {
      output: cleaned
    }
  }
];

let requests = $("Download Document").all()

requests.forEach((request) => {
  let mime_type = request.json.mime_type

  if (
    mime_type === "text/calendar" || 
    mime_type === "application/ics" || 
    mime_type === "text/x-calendar"
  ) {
    request.json.mime_type = "mapped/calendar"
  }

  if (
    mime_type === "application/xml" || 
    mime_type === "text/xml") {
    request.json.mime_type = "mapped/xml"
  }

  if (!mime_type) {
    // חילוץ extension מה-binary data
    const fileName = request.binary?.data?.fileName || '';
    const extension = fileName.split('.').pop()?.toLowerCase();

    // מיפוי extensions ל-MIME types
    const mimeMap = {
      'ics': 'text/calendar',
      'xml': 'application/xml',
      'pdf': 'application/pdf',
      'jpg': 'image/jpeg',
      'jpeg': 'image/jpeg',
      'png': 'image/png',
      'txt': 'text/plain'
    };

    request.json.mime_type = mimeMap[extension] || 'application/octet-stream';
  }
})

return requests;

